import{_ as o,H as a,f as s,i as r}from"./chunks/framework.DbTCwA-u.js";const g=JSON.parse('{"title":"Solução de Problemas","description":"Problemas comuns e soluções ao usar o EligiusNametag.","frontmatter":{"title":"Solução de Problemas","description":"Problemas comuns e soluções ao usar o EligiusNametag."},"headers":[],"relativePath":"pt/troubleshooting.md","filePath":"pt/troubleshooting.md"}'),t={name:"pt/troubleshooting.md"};function n(i,e,l,d,c,u){return a(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="solucao-de-problemas-troubleshooting" tabindex="-1">Solução de Problemas (Troubleshooting) <a class="header-anchor" href="#solucao-de-problemas-troubleshooting" aria-label="Permalink to &quot;Solução de Problemas (Troubleshooting)&quot;">​</a></h1><p>Tendo problemas com o EligiusNametag? Verifique estas soluções comuns:</p><h3 id="_1-a-nametag-nao-aparece-acima-do-jogador" tabindex="-1">1. A Nametag não aparece acima do jogador <a class="header-anchor" href="#_1-a-nametag-nao-aparece-acima-do-jogador" aria-label="Permalink to &quot;1. A Nametag não aparece acima do jogador&quot;">​</a></h3><ul><li><strong>Você tem o ProtocolLib instalado?</strong> Nosso plugin depende estritamente da injeção de pacotes para que as nametags flutuem suavemente sem causar lag.</li><li><strong>Você tem o PlaceholderAPI instalado?</strong> Se você usa variáveis como <code>%vault_rank%</code> e não tem o PAPI, o texto pode não renderizar.</li></ul><h3 id="_2-erro-database-connection-closed" tabindex="-1">2. Erro &quot;Database Connection Closed&quot; <a class="header-anchor" href="#_2-erro-database-connection-closed" aria-label="Permalink to &quot;2. Erro &quot;Database Connection Closed&quot;&quot;">​</a></h3><ul><li>Isso foi <strong>corrigido em versões recentes</strong>. Certifique-se de estar executando a versão mais recente <code>v1.x.x</code> ou superior. Se você usa <strong>MySQL</strong>, verifique se o IP e as credenciais no <code>config.yml</code> estão corretos. Caso contrário, use <code>SQLITE</code> local.</li></ul><h3 id="_3-avisos-do-viaversion-no-console" tabindex="-1">3. Avisos do ViaVersion no Console <a class="header-anchor" href="#_3-avisos-do-viaversion-no-console" aria-label="Permalink to &quot;3. Avisos do ViaVersion no Console&quot;">​</a></h3><p>Se você usa o ViaVersion para permitir que jogadores na 1.20 entrem no seu servidor 1.21+, você pode ver mensagens sobre <em>Metadata</em> e <em>Protocol Versions</em>.</p><ul><li><strong>Causa:</strong> O cliente antigo (ex: 1.20.2) não possui o código nativo para processar entidades <code>TEXT_DISPLAY</code> grandes corretamente.</li><li><strong>Solução:</strong> Recomendamos fortemente exigir versões 1.21+ para visualização perfeita dos hologramas, ou simplesmente ignore o aviso se o jogador não tiver problemas visuais.</li></ul><h3 id="_4-enametag-lang-nao-atualiza-a-mensagem-de-ajuda" tabindex="-1">4. /enametag lang não atualiza a mensagem de ajuda <a class="header-anchor" href="#_4-enametag-lang-nao-atualiza-a-mensagem-de-ajuda" aria-label="Permalink to &quot;4. /enametag lang não atualiza a mensagem de ajuda&quot;">​</a></h3><p>Ao usar <code>/enametag lang pt</code>, o plugin lê de <code>lang/pt.yml</code>. Se você notar que alguma tradução está vazia ou um comando age estranho, você pode deletar a pasta <code>lang/</code> no diretório de plugins para que o EligiusNametag possa regenerá-la de forma limpa com os padrões mais recentes.</p>',11)])])}const p=o(t,[["render",n]]);export{g as __pageData,p as default};
